import{_,r as o,o as a,c,d,w as s,b as e,a as t}from"./app-dabf1657.js";const u={},h=t("h1",{id:"锻炼那些事🏃",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#锻炼那些事🏃","aria-hidden":"true"},"#"),e(" 锻炼那些事🏃")],-1),p=t("p",null,"锻炼：从开始到放弃（2020年7月31日）",-1),r=t("p",null,"其实“锻炼”这种活动在我的过去二十几年算是比较少有的，毕竟我还是喜欢“脑力活动”（玩电脑游戏）多一点。所以激励我去锻炼往往是因为某些事情“不得不去做”的决定，现在来梳理一下我锻炼的经历吧。",-1),K=t("p",null,"初中：打篮球。那会儿正长个子，身体很瘦，拿我妈的话来讲就是“瘦得像条藤”——腰又长又不挺拔。但是也只是在体育课间稍微玩一会儿，不是特别着迷。",-1),v=t("p",null,"高中：不太记得有什么运动项目了……",-1),G=t("p",null,"大学：健身房、骑行",-1),f=t("p",null,"在2013年参加暑期赴美实习后，一开始因为倒时差前几天都睡不着，体重也一直跟着暴瘦，回来第三个月（2013.9.20）就瘦了3公斤，2013.11.19是66.6KG，谷值是61.7KG（2014.4.11）。当时我奶奶看到我那么瘦都直抹眼泪，因为瘦得成人干看起来真惨，后来暑假回海口还去看了医生，医生说疑似桥本甲状腺炎，但是也没有吃什么药。",-1),b=t("p",null,"后来觉得这样不太行，刚好我爸又一时冲动买了一辆捷安特自行车（2014年8月），所以我就顺便骑车锻炼了。幸亏当时几次骑行记录都用咕咚运动记录了下来（7次，4天，55.3公里），我便手工按照当时的记录添加到GARMIN里面了。2014.08.26回升到65KG，2015.08.26回升到71KG。不过后来2016年春节因为和爸妈去韩国玩着凉感冒，体重又一直往下掉，2016.2.17掉到了64.9KG，2017年才又恢复到70KG以上。",-1),A=t("p",null,"工作后：健身房、长跑、慢跑",-1),g=t("p",null,"15-16年，在深粮上班不是特别忙，所以就在翠竹沃尔玛楼上的健身房办了会员卡，在健身房瞎练了1-2年。",-1),m=t("p",null,"17年后由于一直和我家宝“好吃懒做”，再加上人的年纪也大了（快奔三），所以导致体重一直狂飙。从2018年2月的71.1KG一直往上攀升，达到81.4KG（2019.7.21）。后来看到自己的脸和肚子实在惨不忍睹，就在2019年8月31日买了跑步机，下定决心减肥。",-1),x=t("p",null,[e("减肥的效果也和运动量直接挂钩，我2019.12-2020.2月跑量分别是101.9KM、148.5"),t("br"),e(" KM、142.7 KM，所以很惊喜地发现体重在2020.3.15回落到了71.4KG。")],-1),M=t("p",null,"不过由于天气太热产生懒惰之心，从3月后就不怎么想跑步了，因此到7月份体重又回升到75KG左右。",-1),w=t("p",null,"总结：在2019.8.31-2020.7.31期间，我总共跑了773.2公里，跑步95次",-1),N=t("p",null,"锻炼：从放弃到重新开始（2021年8月26日）",-1),B=t("p",null,"自去年7月份体重有了基本的控制后，跑步就稍显动力没那么足了，加上去年8月份搬到了龙海家园，不得不把跑步机卖掉后，跑步的意愿也略为下降。不过后面定了12.30办婚礼的计划，重拾了减肥的动力，因此去年10-11月的跑量都在50KG左右，稍微控制了一下体重，婚前体重大概控制在77KG左右。",-1),T=t("p",null,"后面噩梦就开始了，今年春节决定留深过年，买了台式机然后宅在家里玩赛博朋克2077，加上胡吃海塞，今年3.6体重升到了80.2KG，紧接着4.16升到了82.0KG。充满求生欲的我赶紧拼一把，4月份跑量50KM（还记得4.17那天早上到儿童公园顶着大太阳跑了5公里，跑完后还换了一次性内裤），好歹把体重又拉回80KG左右。然后5-6月份又重复了该死的轮回，体重和饮食反弹，终于到6.24到达了82.2巅峰！唉，天太热，路跑太艰难，肚子甩不掉啊！",-1),V=t("p",null,"不行了不行了，眼见肚子肥肉越来越多，脸变得越来越宽，感觉自己已经到彻底压不住体重的边缘。刚好7月底因为换工作到了华大基因，在翠竹附近的金福大厦找了个两房一厅，面积60多平真够大，所以在8.8下单买了一台爱康跑步机，开始了我又一轮的减肥大计。",-1),j=t("p",null,[e("不得不说，在跑步机上面跑步就是爽，从精神和环境都感觉很舒适，不会因为外面天气热而犹豫导致不想去外面跑。吹空调，看视频跑步美滋滋！（是的，这一次的跑步机是4999大洋入手，通过iFit"),t("br"),e(" app的视频可以实现坡度、速度动态调节，而且视频里的教练是说英语的，全当联系英语听力阅读了）")],-1),k=t("p",null,"总结：在2020.8.1-2021.8.26期间，我总共跑了305.46公里，跑步47次。其中8月在跑步机上总共跑了29.85公里、6次，目前体重81.3KG",-1),y=t("figure",null,[t("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/article/Arthur/2022深圳宝安马拉松（半马）.jpg",alt:"2022深圳宝安马拉松（半马）",width:"400",tabindex:"0",loading:"lazy"}),t("figcaption",null,"2022深圳宝安马拉松（半马）")],-1),z=t("figure",null,[t("img",{src:"https://pan.4a1801.life/d/Onedrive-4A1801/个人建站/assets/article/Arthur/2023深圳盐田山海半程马拉松.jpg",alt:"2023深圳盐田山海半程马拉松",width:"400",tabindex:"0",loading:"lazy"}),t("figcaption",null,"2023深圳盐田山海半程马拉松")],-1);function C(O,E){const n=o("Tabs");return a(),c("div",null,[h,d(n,{id:"3",data:[{id:"从开始到放弃"},{id:"放弃到重新开始"},{id:"马拉松证书"}],active:0},{title0:s(({value:l,isActive:i})=>[e("从开始到放弃")]),title1:s(({value:l,isActive:i})=>[e("放弃到重新开始")]),title2:s(({value:l,isActive:i})=>[e("马拉松证书")]),tab0:s(({value:l,isActive:i})=>[p,r,K,v,G,f,b,A,g,m,x,M,w]),tab1:s(({value:l,isActive:i})=>[N,B,T,V,j,k]),tab2:s(({value:l,isActive:i})=>[y,z]),_:1})])}const I=_(u,[["render",C],["__file","日记里的我-锻炼那些事.html.vue"]]);export{I as default};
